#!/usr/bin/env python3
"""Lightweight CLI for running read-only SQL queries across CSV files."""

import argparse
import os
import re
import sys
from pathlib import Path
from typing import Optional
import pandas as pd
import numpy as np


class CSVDataLoader:
    """Load and manage CSV files from a directory."""

    def __init__(self, data_dir: str):
        self.data_dir = Path(data_dir)
        self.tables = {}
        self._load_all_csvs()

    def _load_all_csvs(self):
        """Load all CSV files recursively, handling nested directories."""
        for csv_path in self.data_dir.rglob("*.csv"):
            # Build table name - replace path separators with dots
            rel_path = csv_path.relative_to(self.data_dir)
            table_name = str(rel_path.with_suffix(""))
            # Replace path separators with dots for nested dirs, then replace any existing dots with underscores
            table_name = table_name.replace(os.sep, ".").replace(".", "_")

            try:
                df = pd.read_csv(csv_path, dtype=str)  # Read as strings initially
                # Replace empty strings with NaN for proper NULL handling
                df = df.replace(r'^\s*$', np.nan, regex=True)
                df = df.replace('NULL', np.nan)  # Treat literal NULL as NaN
                self.tables[table_name] = df
            except Exception as e:
                print(f"Warning: Could not load {csv_path}: {e}", file=sys.stderr)

    def get_table(self, name: str) -> pd.DataFrame:
        """Get a table by name (case-sensitive)."""
        if name not in self.tables:
            raise ValueError(f"Table '{name}' not found. Available: {list(self.tables.keys())}")
        return self.tables[name]


class SQLParser:
    """Parse SQL queries into structured components."""

    def __init__(self, sql: str):
        self.sql = sql.strip()
        self.pos = 0
        self.tokens = self._tokenize()

    def _tokenize(self) -> list:
        """Break SQL into tokens."""
        # Regex for SQL tokens
        token_pattern = re.compile(r"\s*(=>|!=|<=|>=|\b(?:SELECT|FROM|WHERE|GROUP\s+BY|HAVING|ORDER\s+BY|LIMIT|OFFSET|INNER|LEFT|RIGHT|FULL\s+JOIN|ON|AND|OR|NOT|ASC|DESC|DISTINCT|LIKE|COUNT|SUM|MIN|MAX|AS)\b|\w+|'[^']*'|\"[^\"]*\"|[(),])")
        tokens = []
        for match in token_pattern.finditer(self.sql.upper()):
            token = match.group(0).strip()
            if token:
                tokens.append((token, match.group(0)))
        return tokens

    def parse_select_list(self) -> list:
        """Parse SELECT clause."""
        idx = self._skip_to("SELECT")
        if idx == -1:
            raise ValueError("No SELECT clause found")

        idx += 1  # Skip SELECT

        # Check for DISTINCT
        distinct = False
        if idx < len(self.tokens) and self.tokens[idx][0] == "DISTINCT":
            distinct = True
            idx += 1

        select_items = []
        while idx < len(self.tokens) and self.tokens[idx][0] not in ("FROM",):
            if self.tokens[idx][0] == ",":
                idx += 1
                continue

            # Parse item - could be *, column_ref, aggregate, or alias
            item = self._parse_select_item(idx)
            if item:
                select_items.append(item)
                idx = item['end_idx'] + 1
            else:
                break

        return {'items': select_items, 'distinct': distinct}

    def _parse_select_item(self, idx):
        """Parse a single SELECT item."""
        if idx >= len(self.tokens):
            return None

        token_upper, token = self.tokens[idx]

        # Handle *
        if token_upper == "*":
            return {'type': 'wildcard', 'end_idx': idx}

        # Handle aggregate functions
        if token_upper in ("COUNT", "SUM", "MIN", "MAX"):
            if idx + 1 < len(self.tokens) and self.tokens[idx + 1][0] == "(":
                # Find matching closing parenthesis
                close_idx = self._find_matching_paren(idx + 2)
                if close_idx == -1:
                    raise ValueError(f"Unmatched parenthesis for {token_upper}")

                # Get the argument inside parentheses
                args = []
                i = idx + 2
                while i < close_idx:
                    if self.tokens[i][0] != ",":
                        args.append(self.tokens[i][0])
                    i += 1

                func_name = token_upper
                end_idx = close_idx

                # Check for AS alias
                alias = None
                if end_idx + 2 < len(self.tokens) and self.tokens[end_idx + 1][0] == "AS":
                    alias = self.tokens[end_idx + 2][1]
                    end_idx += 2

                return {
                    'type': 'aggregate',
                    'function': func_name,
                    'args': args,
                    'alias': alias,
                    'end_idx': end_idx
                }

        # Handle regular column reference
        end_idx = idx
        alias = None

        # Check for AS or implicit alias
        if idx + 2 < len(self.tokens) and self.tokens[idx + 1][0] == "AS":
            alias = self.tokens[idx + 2][1]
            end_idx = idx + 2
        elif idx + 1 < len(self.tokens) and self.tokens[idx + 1][0] not in (",", "FROM", "WHERE", "GROUP BY", "HAVING", "ORDER BY", "LIMIT", "OFFSET"):
            # Implicit alias without AS keyword
            alias = self.tokens[idx + 1][1]
            end_idx = idx + 1

        return {'type': 'column', 'name': self._normalize_column_ref(token), 'alias': alias, 'end_idx': end_idx}

    def _normalize_column_ref(self, ref: str) -> str:
        """Normalize column reference (remove quotes, handle table prefixes)."""
        if ref.startswith("'") or ref.startswith('"'):
            ref = ref[1:-1]
        return ref.upper()

    def _find_matching_paren(self, start_idx: int) -> int:
        """Find the matching closing parenthesis."""
        count = 1
        idx = start_idx
        while idx < len(self.tokens) and count > 0:
            if self.tokens[idx][0] == "(":
                count += 1
            elif self.tokens[idx][0] == ")":
                count -= 1
                if count == 0:
                    return idx
            idx += 1
        return -1

    def _skip_to(self, keyword: str) -> int:
        """Find the index of a keyword token."""
        for i, (upper, _) in enumerate(self.tokens):
            if upper == keyword:
                return i
        return -1


class SimpleQueryEngine:
    """Execute simplified SQL queries on pandas DataFrames."""

    def __init__(self, data_loader: CSVDataLoader):
        self.loader = data_loader

    def execute(self, sql: str) -> pd.DataFrame:
        """Execute a SQL query and return result DataFrame."""
        sql = sql.strip()
        if not sql.upper().startswith("SELECT"):
            raise ValueError("Query must start with SELECT")

        # Remove trailing semicolon if present
        sql = sql.rstrip(';')

        # Parse the query
        parsed = self._parse_query(sql)

        # Execute
        return self._execute_parsed(parsed)

    def _parse_query(self, sql: str) -> dict:
        """Parse the complete query."""
        result = {}
        sql_upper = sql.upper()

        # Extract SELECT clause
        select_match = re.match(r'SELECT\s+', sql, re.IGNORECASE)
        if not select_match:
            raise ValueError("No SELECT clause found")

        start = select_match.end()

        # Find FROM
        from_match = re.search(r'\s+FROM\s+', sql[start:], re.IGNORECASE)
        if not from_match:
            raise ValueError("No FROM clause found")

        select_end = start + from_match.start()
        result['select'] = sql[start:select_end].strip()

        # Get remaining after FROM
        after_from = sql[start + from_match.end():]

        # Parse FROM table reference (could include JOIN)
        result['tables'] = []
        result['joins'] = []
        result['where'] = None
        result['group_by'] = None
        result['having'] = None
        result['order_by'] = None
        result['limit'] = None
        result['offset'] = None

        # Find next clause or end
        next_clause_match = re.search(
            r'\s+(WHERE|GROUP\s+BY|HAVING|ORDER\s+BY|LIMIT|OFFSET|\s*$)',
            after_from, re.IGNORECASE
        )

        if next_clause_match:
            from_part = after_from[:next_clause_match.start()].strip()
            rest = after_from[next_clause_match.start():].strip()
        else:
            from_part = after_from.strip()
            rest = ''

        # Parse FROM and JOINs
        table_refs = self._parse_table_references(from_part)
        result['tables'] = table_refs

        # Parse remaining clauses
        if rest:
            result = self._parse_remaining_clauses(rest, result)

        return result

    def _parse_table_references(self, from_part: str) -> list:
        """Parse FROM and JOIN clauses."""
        tables = []

        # First, handle the main table
        # Split by JOIN keywords
        parts = re.split(r'\s+(?:INNER|LEFT|RIGHT|FULL)\s+JOIN\s+', from_part, flags=re.IGNORECASE)

        if parts:
            main_table = parts[0].strip()
            # Check for AS alias
            alias_match = re.match(r'([\w.]+)(?:\s+AS\s+(\w+))?', main_table, re.IGNORECASE)
            if alias_match:
                table_name = alias_match.group(1)
                alias = alias_match.group(2) if alias_match.group(2) else None
                tables.append({
                    'name': table_name,
                    'alias': alias,
                    'join_type': None
                })
            else:
                tables.append({'name': main_table, 'alias': None, 'join_type': None})

        # Parse JOINs from remaining parts
        for i, part in enumerate(parts[1:], 1):
            # Determine join type from the original string
            join_keywords = ['INNER JOIN', 'LEFT JOIN', 'RIGHT JOIN', 'FULL JOIN']
            join_type = None
            for jk in join_keywords:
                if jk in from_part[:from_part.find(parts[i-1]) + len(parts[i-1]):]:
                    join_type = jk.split()[0]  # INNER, LEFT, RIGHT, FULL
                    break

            # Parse the JOIN table and ON condition
            # Format: table_ref [AS alias] ON predicate
            if ' ON ' in part.upper():
                on_split = re.split(r'\s+ON\s+', part, maxsplit=1, flags=re.IGNORECASE)
                table_part = on_split[0].strip()
                on_predicate = on_split[1].strip() if len(on_split) > 1 else None
            else:
                table_part = part
                on_predicate = None

            # Parse table name and alias
            alias_match = re.match(r'([\w.]+)(?:\s+AS\s+(\w+))?', table_part, re.IGNORECASE)
            if alias_match:
                table_name = alias_match.group(1)
                alias = alias_match.group(2) if alias_match.group(2) else None
            else:
                table_name = table_part
                alias = None

            tables.append({
                'name': table_name,
                'alias': alias,
                'join_type': join_type,
                'on_predicate': on_predicate
            })

        return tables

    def _parse_remaining_clauses(self, rest: str, result: dict) -> dict:
        """Parse WHERE, GROUP BY, HAVING, ORDER BY, LIMIT, OFFSET clauses."""
        # Find each clause
        clauses = ['WHERE', 'GROUP BY', 'HAVING', 'ORDER BY', 'LIMIT', 'OFFSET']

        for clause in clauses:
            pattern = rf'{clause}\s+'
            match = re.search(pattern, rest, re.IGNORECASE)
            if match:
                clause_start = match.end()
                # Find end of this clause (next clause or end)
                next_clause_pos = len(rest)
                for next_clause in clauses:
                    if next_clause != clause:
                        next_match = re.search(rf'\s+{next_clause}\s+', rest[clause_start:], re.IGNORECASE)
                        if next_match:
                            next_clause_pos = min(next_clause_pos, clause_start + next_match.start())

                clause_value = rest[clause_start:next_clause_pos].strip()

                if clause == 'WHERE':
                    result['where'] = clause_value
                elif clause == 'GROUP BY':
                    result['group_by'] = [c.strip() for c in clause_value.split(',')]
                elif clause == 'HAVING':
                    result['having'] = clause_value
                elif clause == 'ORDER BY':
                    result['order_by'] = clause_value
                elif clause == 'LIMIT':
                    try:
                        result['limit'] = int(clause_value)
                    except ValueError:
                        raise ValueError(f"Invalid LIMIT value: {clause_value}")
                elif clause == 'OFFSET':
                    try:
                        result['offset'] = int(clause_value)
                    except ValueError:
                        raise ValueError(f"Invalid OFFSET value: {clause_value}")

        return result

    def _execute_parsed(self, parsed: dict) -> pd.DataFrame:
        """Execute a parsed query."""
        # Load all tables
        tables_data = []
        table_aliases = {}

        for tbl in parsed['tables']:
            df = self.loader.get_table(tbl['name'])
            df = df.copy()
            df._table_name = tbl['name']  # Store original table name
            tables_data.append(df)

            if tbl['alias']:
                table_aliases[tbl['alias'].upper()] = tbl['name']
            else:
                table_aliases[tbl['name'].upper()] = tbl['name']

        # Handle JOINs if present
        if len(parsed['tables']) > 1:
            merged_df = self._perform_join(tables_data, parsed['tables'])
        else:
            merged_df = tables_data[0]

        # Apply WHERE clause
        if parsed['where']:
            merged_df = self._apply_where(merged_df, parsed['where'], table_aliases)

        # Parse SELECT items
        select_items, distinct = self._parse_select_items(parsed['select'])

        # Handle GROUP BY
        group_cols = None
        if parsed['group_by']:
            group_cols = self._resolve_columns(parsed['group_by'], table_aliases, merged_df)
            # Rename to standardized names if aliases exist
            for i, col in enumerate(group_cols):
                original_col = col
                # Check if this column was given an alias in SELECT
                for item in select_items:
                    if item.get('original_col') == original_col and item.get('alias'):
                        group_cols[i] = item['alias'].upper()

        # Aggregate or select columns
        if any(item.get('type') == 'aggregate' for item in select_items) or group_cols:
            result_df = self._apply_aggregations(merged_df, select_items, group_cols)
        else:
            result_df = self._apply_select(merged_df, select_items)

        # Apply DISTINCT
        if distinct:
            result_df = result_df.drop_duplicates()

        # Apply HAVING
        if parsed['having']:
            result_df = self._apply_having(result_df, parsed['having'], group_cols, select_items, table_aliases)

        # Apply ORDER BY
        if parsed['order_by']:
            result_df = self._apply_order_by(result_df, parsed['order_by'], select_items, table_aliases)

        # Apply LIMIT
        if parsed['limit'] is not None:
            result_df = result_df.head(parsed['limit'])

        # Apply OFFSET
        if parsed['offset'] is not None:
            result_df = result_df.iloc[parsed['offset']:]

        return result_df

    def _perform_join(self, tables: list, table_refs: list) -> pd.DataFrame:
        """Perform JOIN operations on DataFrames."""
        result = tables[0]

        for i, tbl in enumerate(table_refs[1:], 1):
            right_df = tables[i]

            # Parse ON condition
            if tbl.get('on_predicate'):
                on_predicate = tbl['on_predicate'].upper()
                # Parse equality predicate (simplified: column = column)
                if '=' in on_predicate:
                    left_col, right_col = on_predicate.split('=', 1)
                    left_col = left_col.strip()
                    right_col = right_col.strip()

                    # Resolve table prefixes
                    left_col = self._resolve_column_with_table(left_col, result)
                    right_col = self._resolve_column_with_table(right_col, right_df)

                    join_type = tbl.get('join_type', 'INNER') or 'INNER'

                    # Perform join
                    result = pd.merge(
                        result, right_df,
                        left_on=left_col,
                        right_on=right_col,
                        how=join_type.lower(),
                        suffixes=('_left', '_right')
                    )

        return result

    def _resolve_column_with_table(self, col: str, df: pd.DataFrame) -> str:
        """Resolve a column reference to actual DataFrame column name."""
        # Remove quotes if present
        col = col.strip("'\"")

        # If column has table prefix, handle it
        if '.' in col:
            parts = col.split('.')
            # Check if the table alias/name exists
            return col
        else:
            # Simple column reference - check if exists in DataFrame
            if col.upper() in [c.upper() for c in df.columns]:
                # Get the actual case-sensitive column name
                for c in df.columns:
                    if c.upper() == col.upper():
                        return c
            return col

    def _apply_where(self, df: pd.DataFrame, where_clause: str, table_aliases: dict) -> pd.DataFrame:
        """Apply WHERE clause to DataFrame."""
        # This is a simplified implementation that uses pandas query
        # Convert SQL-like WHERE to pandas query syntax
        pandas_query = self._sql_to_pandas_query(where_clause, table_aliases, df)

        try:
            return df.query(pandas_query)
        except Exception as e:
            raise ValueError(f"Error in WHERE clause: {e}")

    def _sql_to_pandas_query(self, sql_expr: str, table_aliases: dict, df: pd.DataFrame) -> str:
        """Convert a simplified SQL WHERE expression to pandas query syntax."""
        # This is a simplistic converter
        expr = sql_expr.upper()

        # Handle LIKE
        expr = re.sub(r"(\w+)\s+LIKE\s+'([^']*)'", r'\1.str.contains(\'\2\', na=False)', expr)

        # Handle comparisons
        expr = re.sub(r'!=', '!=', expr)
        expr = re.sub(r'=\s*(?!\s*=)', '==', expr)
        expr = re.sub(r'\b(<|>|<=|>=)\b', r'\1', expr)

        # Handle string literals
        def replace_literal(match):
            return f"'{match.group(0).strip(\"'\\\"\"')}"
        expr = re.sub(r"'[^']*'|\"[^\"]*\"", replace_literal, expr)

        # Handle boolean operators
        expr = expr.replace(' AND ', ' and ').replace(' OR ', ' or ').replace(' NOT ', ' not ')

        # Handle parentheses
        expr = expr.replace('(', '').replace(')', '')

        return expr

    def _parse_select_items(self, select_str: str) -> tuple:
        """Parse SELECT clause items."""
        items = []
        distinct = 'DISTINCT' in select_str.upper()

        # Remove DISTINCT keyword
        select_clean = re.sub(r'^\s*DISTINCT\s+', '', select_str, flags=re.IGNORECASE)

        # Split by comma
        parts = [p.strip() for p in select_clean.split(',')]

        for part in parts:
            if not part:
                continue

            # Handle *
            if part == '*':
                items.append({'type': 'wildcard'})
                continue

            # Handle aggregates
            agg_match = re.match(r'(COUNT|SUM|MIN|MAX)\s*\(([^)]+)\)\s*(?:AS\s+(\w+))?', part, re.IGNORECASE)
            if agg_match:
                func = agg_match.group(1).upper()
                args = agg_match.group(2).strip()
                alias = agg_match.group(3) if agg_match.group(3) else None

                # Parse aggregate arguments
                if args == '*':
                    agg_args = ['*']
                else:
                    agg_args = [a.strip() for a in args.split(',')]

                items.append({
                    'type': 'aggregate',
                    'function': func,
                    'args': agg_args,
                    'alias': alias
                })
                continue

            # Handle regular column with optional alias
            alias_match = re.match(r'([\w.]+)\s+AS\s+(\w+)', part, re.IGNORECASE)
            if alias_match:
                items.append({
                    'type': 'column',
                    'name': alias_match.group(1),
                    'alias': alias_match.group(2)
                })
                continue

            # Handle implicit alias
            alias_match = re.match(r'([\w.]+)\s+(\w+)$', part, re.IGNORECASE)
            if alias_match:
                items.append({
                    'type': 'column',
                    'name': alias_match.group(1),
                    'alias': alias_match.group(2)
                })
                continue

            # Handle column reference
            items.append({
                'type': 'column',
                'name': part
            })

        return items, distinct

    def _resolve_columns(self, cols: list, table_aliases: dict, df: pd.DataFrame) -> list:
        """Resolve column names considering aliases and table prefixes."""
        resolved = []
        for col in cols:
            col = col.strip()
            # Handle table prefix
            if '.' in col:
                parts = col.split('.')
                resolved.append(col)
            else:
                # Check if this matches an alias in SELECT
                found = False
                for c in df.columns:
                    if c.upper() == col.upper():
                        resolved.append(c)
                        found = True
                        break
                if not found:
                    resolved.append(col)
        return resolved

    def _apply_select(self, df: pd.DataFrame, select_items: list) -> pd.DataFrame:
        """Apply SELECT clause to DataFrame."""
        result_cols = []

        for item in select_items:
            if item['type'] == 'wildcard':
                # Select all columns
                for col in df.columns:
                    col_name = item.get('alias') if item.get('alias') and 'table.' not in col else col
                    result_cols.append(col)
            elif item['type'] == 'column':
                col_name = item['name']
                # Find matching column in DataFrame (case-insensitive)
                matched_col = None
                for c in df.columns:
                    if c.upper() == col_name.upper() or c == col_name:
                        matched_col = c
                        break

                if matched_col:
                    result_cols.append((matched_col, item.get('alias')))
                else:
                    # Column not found, create empty column
                    result_cols.append((col_name, item.get('alias')))

        # Build result DataFrame
        result_df = pd.DataFrame()
        for col, alias in result_cols:
            if col in df.columns:
                result_df[alias if alias else col] = df[col]
            else:
                result_df[alias if alias else col] = None

        return result_df

    def _apply_aggregations(self, df: pd.DataFrame, select_items: list, group_cols: list) -> pd.DataFrame:
        """Apply aggregation functions with GROUP BY support."""
        aggregations = {}
        select_columns = []

        # Build aggregation dictionary for pandas groupby
        for item in select_items:
            if item['type'] == 'aggregate':
                func = item['function'].lower()
                for arg in item['args']:
                    if arg == '*':
                        # COUNT(*)
                        arg_for_agg = df.columns[0] if len(df.columns) > 0 else None
                        if arg_for_agg:
                            aggregations[arg_for_agg] = 'count'
                    else:
                        # Find matching column
                        matched_col = None
                        for c in df.columns:
                            if c.upper() == arg.upper():
                                matched_col = c
                                break

                        if matched_col:
                            if func == 'count':
                                # Use count of non-null values
                                aggregations[matched_col] = 'count'
                            elif func == 'sum':
                                aggregations[matched_col] = 'sum'
                            elif func == 'min':
                                aggregations[matched_col] = 'min'
                            elif func == 'max':
                                aggregations[matched_col] = 'max'

                        select_columns.append({
                            'col': matched_col or arg,
                            'func': func,
                            'alias': item.get('alias')
                        })
            elif item['type'] == 'column':
                matched_col = None
                for c in df.columns:
                    if c.upper() == item['name'].upper():
                        matched_col = c
                        break
                select_columns.append({
                    'col': matched_col or item['name'],
                    'func': None,
                    'alias': item.get('alias')
                })

        if group_cols:
            # Handle GROUP BY
            groupby_cols = []
            for gcol in group_cols:
                matched = None
                for c in df.columns:
                    if c.upper() == gcol.upper():
                        matched = c
                        break
                if matched:
                    groupby_cols.append(matched)
                else:
                    # Check if it's an alias
                    for sc in select_columns:
                        if sc.get('alias') and sc['alias'].upper() == gcol.upper():
                            groupby_cols.append(sc['col'])
                            break

            result_df = df.groupby(groupby_cols, dropna=False).agg(aggregations)
            result_df = result_df.reset_index()
        else:
            # No GROUP BY - single row result
            result_df = df.agg(aggregations).to_frame().T
            # Reset columns to match select order
            result_df = result_df.reindex(columns=[ag.get('alias', agcol) for agcol, ag in aggregations.items()])

        # Rename columns according to aliases
        final_result = pd.DataFrame()
        for sc in select_columns:
            col = sc['col']
            alias = sc.get('alias')

            if sc['func']:
                # This is an aggregate column
                if col in result_df.columns:
                    if alias:
                        final_result[alias] = result_df[col]
                    else:
                        final_result[col] = result_df[col]
            else:
                # Regular column
                if col in result_df.columns:
                    if alias:
                        final_result[alias] = result_df[col]
                    else:
                        final_result[col] = result_df[col]

        return final_result

    def _apply_having(self, df: pd.DataFrame, having_clause: str, group_cols: list,
                      select_items: list, table_aliases: dict) -> pd.DataFrame:
        """Apply HAVING clause."""
        # Simplified implementation - convert to pandas query
        pandas_query = self._sql_to_pandas_query(having_clause, table_aliases, df)

        try:
            return df.query(pandas_query)
        except Exception as e:
            raise ValueError(f"Error in HAVING clause: {e}")

    def _apply_order_by(self, df: pd.DataFrame, order_by_str: str, select_items: list,
                        table_aliases: dict) -> pd.DataFrame:
        """Apply ORDER BY clause."""
        # Parse order by items
        items = []
        for part in order_by_str.split(','):
            part = part.strip()
            if not part:
                continue

            # Check for ASC/DESC
            ascending = True
            col_name = part

            if part.upper().endswith(' DESC'):
                ascending = False
                col_name = part[:-5].strip()
            elif part.upper().endswith(' ASC'):
                ascending = True
                col_name = part[:-4].strip()

            # Remove quotes if present
            col_name = col_name.strip("'\"")

            # Find matching column in result
            matched_col = None
            for c in df.columns:
                if c.upper() == col_name.upper():
                    matched_col = c
                    break

            if matched_col:
                items.append((matched_col, ascending))
            else:
                # Use position or original name
                items.append((col_name, ascending))

        if items:
            # Build sort list
            sort_cols = []
            for col, ascending in items:
                if col in df.columns:
                    sort_cols.append((col, ascending))

            if sort_cols:
                sort_keys = [col for col, asc in sort_cols]
                ascending_list = [asc for col, asc in sort_cols]
                df = df.sort_values(by=sort_keys, ascending=ascending_list)

        return df


def format_as_markdown_table(df: pd.DataFrame) -> str:
    """Format DataFrame as a markdown table."""
    if df.empty:
        return "| No results |\n|------------|\n|            |\n"

    # Handle NULL values in display
    df_display = df.copy()
    for col in df_display.columns:
        df_display[col] = df_display[col].apply(lambda x: '' if pd.isna(x) else str(x))

    # Build header
    header = "| " + " | ".join(str(col) for col in df_display.columns) + " |"

    # Build separator
    separator = "| " + " | ".join(["---"] * len(df_display.columns)) + " |"

    # Build rows
    rows = []
    for _, row in df_display.iterrows():
        row_str = "| " + " | ".join(str(val) for val in row.values) + " |"
        rows.append(row_str)

    return "\n".join([header, separator] + rows) + "\n"


def format_as_csv(df: pd.DataFrame) -> str:
    """Format DataFrame as CSV string."""
    if df.empty:
        return ""

    # Handle NULL values - use empty string
    df_output = df.copy()
    for col in df_output.columns:
        df_output[col] = df_output[col].apply(lambda x: '' if pd.isna(x) else str(x))

    return df_output.to_csv(index=False)


def parse_sql_input(sql_input: str) -> str:
    """Parse SQL input which could be raw SQL or a file path."""
    sql_input = sql_input.strip()

    # Check if it's a file path
    if os.path.isfile(sql_input):
        with open(sql_input, 'r') as f:
            return f.read().strip()

    return sql_input


def main():
    parser = argparse.ArgumentParser(
        description="Run read-only SQL queries on CSV files."
    )
    parser.add_argument(
        '--data',
        required=True,
        help='Directory containing CSV files (can be nested)'
    )
    parser.add_argument(
        '--sql',
        required=True,
        help='Raw SQL query or path to SQL file'
    )
    parser.add_argument(
        '--out',
        required=False,
        help='Path to output CSV file (optional)'
    )

    args = parser.parse_args()

    # Validate data directory
    if not os.path.isdir(args.data):
        print(f"Error: Data directory not found: {args.data}", file=sys.stderr)
        sys.exit(1)

    # Parse SQL input
    try:
        sql = parse_sql_input(args.sql)
    except FileNotFoundError:
        print(f"Error: SQL file not found: {args.sql}", file=sys.stderr)
        sys.exit(1)

    # Load data
    try:
        loader = CSVDataLoader(args.data)
    except Exception as e:
        print(f"Error loading data: {e}", file=sys.stderr)
        sys.exit(1)

    # Execute query
    try:
        engine = SimpleQueryEngine(loader)
        result_df = engine.execute(sql)

        # Format output
        markdown_table = format_as_markdown_table(result_df)
        print(markdown_table)

        # Write to output file if specified
        if args.out:
            csv_output = format_as_csv(result_df)
            with open(args.out, 'w') as f:
                f.write(csv_output)

    except Exception as e:
        print(f"Error executing query: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

